const responser = require('express-responser');
const router = require('./router');
const badgeFunctions = require('./badgeFunctions');

let config;

module.exports.appStart = (_config, app) => {
  config = _config;
  router.addRoute(app, _config);
};


module.exports.get = serviceInit => ({
  create: (id, _subjectType) => {
    const functions = badgeFunctions.init(serviceInit);
    return functions.createBadge(id, _subjectType);
  },
});

module.exports.middleware = (req, res, next) => {
  const functions = badgeFunctions.init(req.serviceInit);

  functions.validate(config);

  if (req.method === 'POST' || req.method === 'PUT') {
    const badgeFields = functions.mapRequestParameters(req.body, req.params);

    functions.createBadges(badgeFields)
      .then(() => next())
      .catch(err => responser.withError(next, err));
  } else { // POST veya PUT degilse hic beklemesin
    return next();
  }
};
